+// =============================================================================
+// Writer Command Types
+// =============================================================================
+
+/// Commands sent to the writer thread
+enum WriteCommand {
+    /// Append a segment (pane_id, content, content_hash, response channel)
+    AppendSegment {
+        pane_id: u64,
+        content: String,
+        content_hash: Option<String>,
+        respond: oneshot::Sender<Result<Segment>>,
+    },
+    /// Record a gap event
+    RecordGap {
+        pane_id: u64,
+        reason: String,
+        respond: oneshot::Sender<Result<Gap>>,
+    },
+    /// Record an event/detection
+    RecordEvent {
+        event: StoredEvent,
+        respond: oneshot::Sender<Result<i64>>,
+    },
+    /// Mark event as handled
+    MarkEventHandled {
+        event_id: i64,
+        workflow_id: Option<String>,
+        status: String,
+        respond: oneshot::Sender<Result<()>>,
+    },
+    /// Upsert a pane record
+    UpsertPane {
+        pane: PaneRecord,
+        respond: oneshot::Sender<Result<()>>,
+    },
+    /// Insert or update a workflow execution
+    UpsertWorkflow {
+        workflow: WorkflowRecord,
+        respond: oneshot::Sender<Result<()>>,
+    },
+    /// Insert a workflow step log
+    InsertStepLog {
+        workflow_id: String,
+        step_index: usize,
+        step_name: String,
+        result_type: String,
+        result_data: Option<String>,
